        public static bool LoginWithAllUsersFromDataSource()
        {
            var credentials = ReadCredentialsFromExcel();

            if (credentials.Count == 0)
            {
                Report.Log(ReportLevel.Error, "Login",
                    "Không tìm thấy credential nào trong Excel");
                return false;
            }

            for (int i = 0; i < credentials.Count; i++)
            {
                string user = credentials[i].Item1;
                string pass = credentials[i].Item2;

                Report.Log(ReportLevel.Info, "Login",
                    string.Format("=== Thử credential {0}/{1}: user '{2}' ===",
                        i + 1, credentials.Count, user));

                if (i > 0)
                    ClearLoginFields();

                if (TryLoginWithUser(user, pass))
                {
                    Report.Log(ReportLevel.Success, "Login",
                        string.Format("Login thành công với user: {0} (lần thử {1})", user, i + 1));
                    return true;
                }

                Report.Log(ReportLevel.Warn, "Login",
                    string.Format("Login thất bại với user: {0}", user));
            }

            Report.Log(ReportLevel.Error, "Login",
                "Không có tài khoản nào login thành công");
            return false;
        }

        public static bool TryLoginWithUser(string user, string pass)
        {
            try
            {
                repo.CCILoginWindow.XIDPWLoginArea.SomeText.Click("47;2");
                Delay.Milliseconds(200);
                Keyboard.Press("{Control}a");
                Delay.Milliseconds(50);
                Keyboard.Press(user);
                Delay.Milliseconds(100);

                repo.CCILoginWindow.XIDPWLoginArea.XPWWatermark.Click("36;6");
                Delay.Milliseconds(200);
                Keyboard.Press("{Control}a");
                Delay.Milliseconds(50);
                Keyboard.Press(pass);
                Delay.Milliseconds(100);

                repo.CCILoginWindow.Login.Click("10;8");
                Delay.Milliseconds(200);

                return IsLoginSuccessful();
            }
            catch (Exception ex)
            {
                Report.Log(ReportLevel.Error, "Login",
                    string.Format("Lỗi khi thử login với user '{0}': {1}", user, ex.Message));
                return false;
            }
        }

        public static void ClearLoginFields()
