        private static List<Tuple<string, string>> ReadCredentialsFromExcel()
        {
            var results = new List<Tuple<string, string>>();

            if (!File.Exists(ExcelPath))
            {
                Report.Log(ReportLevel.Error, "Login",
                    "Không tìm thấy file Excel: " + ExcelPath);
                return results;
            }

            string connStr = string.Format(
                "Provider=Microsoft.ACE.OLEDB.12.0;Data Source={0};" +
                "Extended Properties='Excel 12.0 Xml;HDR=YES;IMEX=1'", ExcelPath);

            try
            {
                using (var conn = new OleDbConnection(connStr))
                {
                    conn.Open();
                    using (var cmd = new OleDbCommand("SELECT [User], [Pass] FROM [Login$]", conn))
                    using (var reader = cmd.ExecuteReader())
                    {
                        while (reader.Read())
                        {
                            string user = reader["User"] != null ? reader["User"].ToString().Trim() : "";
                            string pass = reader["Pass"] != null ? reader["Pass"].ToString().Trim() : "";
                            if (!string.IsNullOrEmpty(user))
                                results.Add(Tuple.Create(user, pass));
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Report.Log(ReportLevel.Error, "Login",
                    "Lỗi đọc Excel: " + ex.Message);
            }

            Report.Log(ReportLevel.Info, "Login",
                string.Format("Đọc được {0} credential từ Excel", results.Count));
            return results;
        }
    }
